        $now = now();
        $floodedAt = $now->copy()->subHours(2);
        $batch = [];

        foreach ($reports as [$extId, $lng, $lat, $wlCm, $floodType, $street, $ward, $district, $polyline]) {
            $batch[] = [
                'external_id'        => $extId,
                'street_name'        => $street,
                'ward_name'          => $ward,
                'district_name'      => $district,
                'longitude'          => $lng,
                'latitude'           => $lat,
                'water_level_cm'     => $wlCm,
                'flood_type'         => $floodType ?: 'street',
                'flood_location_type'=> 'street',
                'polyline'           => $polyline ?: null,
                'is_frequent'        => false,
                'flood_started_at'   => $floodedAt,
                'reported_at'        => $floodedAt,
                'created_at'         => $now,
                'updated_at'         => $now,
            ];
        }

        foreach (array_chunk($batch, 50) as $chunk) {
            DB::table('flood_reports')->upsert($chunk, ['external_id'], [
                'water_level_cm', 'latitude', 'longitude', 'polyline', 'updated_at',
            ]);
        }

        $this->command->info('✅ FloodReportSeeder: ' . count($batch) . ' flood reports seeded');
    }
